import { extractWriteData, type PathSpec, type RegisteredOp } from '@struktoai/mirage-core'
import { ResourceName } from '@struktoai/mirage-core'
import type { SSHAccessor } from '../../accessor/ssh.ts'
import { writeBytes } from '../../core/ssh/write.ts'

export const writeOp: RegisteredOp = {
  name: 'write',
  resource: ResourceName.SSH,
  filetype: null,
  write: true,
  fn: (accessor: SSHAccessor, path: PathSpec, args: readonly unknown[]) => {
    const data = extractWriteData(args)
    return writeBytes(accessor, path, data)
  },
}
